import{G as t,c as s,b as o,ae as e}from"./chunks/framework.Cpb2nuHT.js";const r="/assets/1763561481002.CaQzHa9g.png",l="/assets/1763561825716.fHfVA5YQ.png",i="/assets/1773146844901.BYznODoM.png",n="/assets/1773147751431.BUyreG8G.png",p="/assets/1773147922431.BsUwC7J1.png",c="/assets/1773148279208.BThg1R7n.png",d="/assets/1773149065353.BdveUeux.png",h="/assets/1773149710167.By769Yun.png",g="/assets/1773151356293.CAsVfSbn.png",m="/assets/1773151388111.BgR9niff.png",_="/assets/1773151667983.B2qpxy04.png",u="/assets/1773665649124.Bdvy6E_-.png",b="/assets/1773665836673.CcS0tPzO.png",q="/assets/1773666079576.BZiqnE1d.png",f="/assets/1773667370511.3oPdNobe.png",v="/assets/1773666716056.f5zeiS3T.png",k="/assets/1773667360059.UzBZBR4G.png",J="/assets/1773668017636.CWHZ7dWu.png",y="/assets/1773668379661.fWE-CN_1.png",x="/assets/1773668615037.BqCxLMkm.png",T=JSON.parse('{"title":"Java 字节码","description":"","frontmatter":{"title":"Java 字节码","date":"2025/11/19 21:57","tags":["Java","JVM"],"author":"花木凋零成兰","hiddenCover":true},"headers":[],"relativePath":"Java/JVM/02_Java字节码.md","filePath":"Java/JVM/02_Java字节码.md","lastUpdated":1775139533000}'),z={name:"Java/JVM/02_Java字节码.md"};function P(j,a,B,C,D,V){return o(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1763589420000"},[...a[0]||(a[0]=[e('<h1 id="java-字节码" tabindex="-1">Java 字节码 <a class="header-anchor" href="#java-字节码" aria-label="Permalink to &quot;Java 字节码&quot;">​</a></h1><h2 id="查看字节码文件" tabindex="-1">查看字节码文件 <a class="header-anchor" href="#查看字节码文件" aria-label="Permalink to &quot;查看字节码文件&quot;">​</a></h2><p>字节码文件保存了源代码编译后的内容, 以二进制形式存储, 无法直接用记事本打开阅读, 使用 <code>CotEditor</code> 文本工具打开内容会有乱码, 如下所示:</p><p><img src="'+r+'" alt="1763561481002" loading="lazy"></p><p>可以使用专门的字节码工具 <a href="https://github.com/ingokegel/jclasslib" target="_blank" rel="noreferrer">jclasslib</a>, 也可以直接在 IDEA 中搜索该工具名称的插件直接使用, 基本界面如下所示:</p><p><img src="'+l+'" alt="1763561825716" loading="lazy"></p><h2 id="字节码文件组成" tabindex="-1">字节码文件组成 <a class="header-anchor" href="#字节码文件组成" aria-label="Permalink to &quot;字节码文件组成&quot;">​</a></h2><h3 id="基础信息" tabindex="-1">基础信息 <a class="header-anchor" href="#基础信息" aria-label="Permalink to &quot;基础信息&quot;">​</a></h3><p>包含魔数、字节码文件对应的 Java 版本号、访问标识、父类和接口等信息;</p><p><img src="'+i+'" alt="字节码-基础信息" loading="lazy"></p><h4 id="魔数" tabindex="-1">魔数 <a class="header-anchor" href="#魔数" aria-label="Permalink to &quot;魔数&quot;">​</a></h4><p><img src="'+n+'" alt="字节码基础信息-魔数" loading="lazy"></p><p>文件<strong>无法通过文件扩展名来确定文件类型</strong>, 文件扩展名可以随意修改, 不会影响文件的内容;</p><p><strong>软件是通过文件的头几个字节(文件头)校验文件类型</strong>, 如果软件不支持该文件类型就会出错; 在 Java 字节码中, 将文件头称为 <strong>magic 魔数</strong>;</p><p><img src="'+p+'" alt="1773147922431" loading="lazy"></p><h4 id="主副版本号" tabindex="-1">主副版本号 <a class="header-anchor" href="#主副版本号" aria-label="Permalink to &quot;主副版本号&quot;">​</a></h4><p><img src="'+c+'" alt="主副版本号" loading="lazy"></p><p>主<strong>副版本号指的是编译字节码文件的 JDK 版本号</strong>:</p><ul><li>主版本号标识大版本, JDK1.0-1.1 使用了 45-45.3, JDK1.2则是 46; 即没升级一个大版本就加 1;</li><li>副版本是当主版本号相同时, 作为区分不同版本的标识, 一般只关心主版本号;</li></ul><p>版本号的作用主要是<strong>判断当前字节码的版本和运行时的 JDK 是否兼容</strong>;</p><blockquote><p>1.2 之后的大版本号计算方法就是: 主版本号-44; 如主版本号为 52 就是 JDK8;</p></blockquote><h4 id="其他信息" tabindex="-1">其他信息 <a class="header-anchor" href="#其他信息" aria-label="Permalink to &quot;其他信息&quot;">​</a></h4><p><img src="'+d+'" alt="1773149065353" loading="lazy"></p><h3 id="常量池和字段" tabindex="-1">常量池和字段 <a class="header-anchor" href="#常量池和字段" aria-label="Permalink to &quot;常量池和字段&quot;">​</a></h3><p>常量池: 保存了字符串常量、类或接口名、字段名,主要在字节码指令中使用; 用于<strong>避免相同的内容重复定义</strong>, 节省空间;</p><p>字段: 当前类或接口声明的字段信息保存在字节码文件中;</p><p>如下所示, 虽然声明了两个内容一样的字符串, 但是在字节码文件中, 两个变量的值都是指向一个常量池中的字符串常量; <img src="'+h+'" alt="1773149710167" loading="lazy"></p><ul><li>常量池中的数据都有一个编号, 编号从 1 开始; 在字段或字节码指令中通过编号可以快速找到对应数据;</li><li>字节码指令中<strong>通过编号引用到常量池</strong>的过程称之为<strong>符号引用</strong>;</li></ul><h3 id="方法" tabindex="-1">方法 <a class="header-anchor" href="#方法" aria-label="Permalink to &quot;方法&quot;">​</a></h3><p>字节码中的方法区域是<strong>存放字节码指令的核心位置</strong>, 字节码指令的内容存放在方法的 Code 属性中;</p><p><img src="'+g+'" alt="1773151356293" loading="lazy"></p><p>方法分析示例 1:</p><p><img src="'+m+'" alt="1773151388111" loading="lazy"></p><p>方法分析示例 2:</p><blockquote><p>最终 i 的值为 0</p></blockquote><p><img src="'+_+'" alt="1773151667983" loading="lazy"></p><h3 id="属性" tabindex="-1">属性 <a class="header-anchor" href="#属性" aria-label="Permalink to &quot;属性&quot;">​</a></h3><p>类的属性, 比如源码的文件名、内部类的列表等;</p><h2 id="java-字节码常用工具" tabindex="-1">Java 字节码常用工具 <a class="header-anchor" href="#java-字节码常用工具" aria-label="Permalink to &quot;Java 字节码常用工具&quot;">​</a></h2><h3 id="java-命令" tabindex="-1">Java 命令 <a class="header-anchor" href="#java-命令" aria-label="Permalink to &quot;Java 命令&quot;">​</a></h3><blockquote><p>使用 javap -v 命令;</p></blockquote><p><img src="'+u+'" alt="1773665649124" loading="lazy"></p><p>javap 是 JDK 自带的反编译工具, 可以通过终端查看字节码文件的内容; 如下所示:</p><blockquote><p>如果是查看 jar 包, 可以通过 <code>jar -xvf 文件名</code> 解压;</p></blockquote><p><img src="'+b+'" alt="1773665836673" loading="lazy"></p><h3 id="jclasslib-插件" tabindex="-1">jclasslib 插件 <a class="header-anchor" href="#jclasslib-插件" aria-label="Permalink to &quot;jclasslib 插件&quot;">​</a></h3><p>在 idea 直接直接下载安装即可; 安装后在【视图】中找到打开字节码即可;</p><p><img src="'+q+'" alt="1773666079576" loading="lazy"></p><h3 id="阿里-arthas" tabindex="-1">阿里 arthas <a class="header-anchor" href="#阿里-arthas" aria-label="Permalink to &quot;阿里 arthas&quot;">​</a></h3><p><a href="https://arthas.aliyun.com/doc/" target="_blank" rel="noreferrer">Arthas</a> 是线上监控诊断产品, 可以实时查看应用 load、内存、gc、线程的状态信息, 能在不修改应用代码的情况下,对业务问题进行诊断;</p><p><img src="'+f+'" alt="1773667370511" loading="lazy"></p><p>在官网下载压缩包后, 解压执行 <code>java -jar arthas-boot.jar</code> 命令启动即可;</p><p><img src="'+v+'" alt="1773666716056" loading="lazy"></p><p>输入想查看的进程编号,点击回车即可查看相关运行程序信息,如下所示:</p><p><img src="'+k+'" alt="1773667360059" loading="lazy"></p><h4 id="查看实时数据面板" tabindex="-1">查看实时数据面板 <a class="header-anchor" href="#查看实时数据面板" aria-label="Permalink to &quot;查看实时数据面板&quot;">​</a></h4><p>指定观察的线程后,再执行命令: <code>dashboard -i 2000 -n 1</code></p><p><img src="'+J+'" alt="1773668017636" loading="lazy"></p><h4 id="移动字节码文件到指定目录" tabindex="-1">移动字节码文件到指定目录 <a class="header-anchor" href="#移动字节码文件到指定目录" aria-label="Permalink to &quot;移动字节码文件到指定目录&quot;">​</a></h4><p>执行命令: <code>dump -d workspace/test 类的全限定名</code></p><p><img src="'+y+'" alt="1773668379661" loading="lazy"></p><h4 id="反编译成类的源代码" tabindex="-1">反编译成类的源代码 <a class="header-anchor" href="#反编译成类的源代码" aria-label="Permalink to &quot;反编译成类的源代码&quot;">​</a></h4><p>执行命令: <code>jad 类的全限定名</code></p><p><img src="'+x+'" alt="1773668615037" loading="lazy"></p><h2 id="问题自测" tabindex="-1">问题自测 <a class="header-anchor" href="#问题自测" aria-label="Permalink to &quot;问题自测&quot;">​</a></h2><p>1、如何查看字节码文件?</p><p>可以使用 javap 命令、jclasslib 工具、阿里云的 arthas 工具;</p><p>2、字节码文件的核心组成有哪些?</p><p><strong>基础信息</strong>、<strong>常量池</strong>、字段、接口、<strong>方法</strong>、属性</p>',69)])])}const A=t(z,[["render",P]]);export{T as __pageData,A as default};
